/**
 * @summary Preview a pending invitation (household + role).
 */
export const previewInvitation = (token: string, signal?: AbortSignal) => {
  return customInstance<InvitationPreviewOut>({
    url: `/api/invitations/${token}`,
    method: "GET",
    signal,
  });
};

export const getPreviewInvitationQueryKey = (token?: string) => {
  return [`/api/invitations/${token}`] as const;
};

export const getPreviewInvitationQueryOptions = <
  TData = Awaited<ReturnType<typeof previewInvitation>>,
  TError = HTTPError,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof previewInvitation>>,
      TError,
      TData
    >;
  },
) => {
  const { query: queryOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getPreviewInvitationQueryKey(token);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof previewInvitation>>
  > = ({ signal }) => previewInvitation(token, signal);

  return {
    queryKey,
    queryFn,
    enabled: !!token,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof previewInvitation>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type PreviewInvitationQueryResult = NonNullable<
  Awaited<ReturnType<typeof previewInvitation>>
>;
export type PreviewInvitationQueryError = HTTPError;

/**
 * @summary Preview a pending invitation (household + role).
 */

export function usePreviewInvitation<
  TData = Awaited<ReturnType<typeof previewInvitation>>,
  TError = HTTPError,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof previewInvitation>>,
      TError,
      TData
    >;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getPreviewInvitationQueryOptions(token, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  query.queryKey = queryOptions.queryKey;

  return query;
}
